/// <summary>
/// 
/// </summary>
/// <param name = "_request"></param>
/// <returns></returns>
public ETGAPayLedgerJournalResponse create(ETGAPayLedgerJournalRequest _request)
{
    List lines;
    ListIterator   literator;
    ETGAPayLedgerJournalTransContract integrationRequestLine;
    int i;

    var response = new ETGAPayLedgerJournalResponse();
    {

        changecompany(_request.parmDataAreaId())
        {
            try
            {
                this.createHeader(_request.parmIntegrationHeaderClass());

                //Create lines
                lines = _request.parmIntegrationLineContractArray();
                if (lines)
                {
                    literator = new ListIterator(lines);
                    while (literator.more())
                    {
                        integrationRequestLine = literator.value();
                        this.createLine(_request.parmIntegrationHeaderClass(), integrationRequestLine);
                        literator.next();
                    }
                }

                //response.parmDebugMessage(_request.parmIntegrationHeaderClass().parmCONTRACTNUMBER());
                response.parmSuccess(true);
                Info(strFmt("%1 Response", response));
            }

            catch (Exception::CLRError)
            {
                System.Exception interopException = CLRInterop::getLastException();

                response.parmSuccess(false);
                response.parmErrorMessage(interopException.ToString());
                Info(strFmt("%1 Response", response));
            }
        }
    }
    return response;
}

/// <summary>
/// 
/// </summary>
/// <param name = "_requestHeader"></param>
public void createHeader(ETGAPayLedgerJournalTableContract _requestHeader)
{
    ETGHapayPurchTable header;

    header.clear();
    header.PurchId = _requestHeader.parmPurchId();
    header.CurrencyCode = _requestHeader.parmCurrencyCode();
    header.ETGDataAreaId = _requestHeader.parmDataAreaId();
    header.DlvTerm = _requestHeader.parmDlvTerm();
    header.VendorName = _requestHeader.parmVendorName();
    header.Vendor = _requestHeader.parmVendor();
    header.DocumentDate = _requestHeader.parmDocumentDate();
    header.InvoiceDate = _requestHeader.parmInvoiceDate();
    header.PaymentTerms = _requestHeader.parmPaymentTerms();
    header.PaymentDueDate = _requestHeader.parmPaymentDueDate();
    header.PlaceOfLoading = _requestHeader.parmPlaceOfLoading();
    header.PlaceOfDischarge = _requestHeader.parmPlaceOfDischarge();
    header.CountryOfOriginOfGoods = _requestHeader.parmCountryOfOriginOfGoods();
    header.CountryOfFinalDestination = _requestHeader.parmCountryOfFinalDestination();
    header.Reference_Number = _requestHeader.parmReferenceNumber();
    header.TradeDetails = _requestHeader.parmTradeDetails();

    header.SharepointURL = _requestHeader.parmSharepointURL();
    header.insert();
}

/// <summary>
/// 
/// </summary>
/// <param name = "_requestHeader"></param>
/// <param name = "_requestLine"></param>
public void createLine(ETGAPayLedgerJournalTableContract _requestHeader, ETGAPayLedgerJournalTransContract _requestLine)
{
    ETGHapayPurchLine lines;

    lines.clear();
    lines.PurchId = _requestHeader.parmPurchId();
    lines.ItemId = _requestLine.parmProductCode();
    lines.PartNo = _requestLine.parmPartNo();
    lines.PurchQty = _requestLine.parmQuantity();
    lines.SupplierInvoiceNo = _requestLine.parmSupplierInvoiceNo();
    lines.BLNo = _requestLine.parmBLNo();
    lines.DeliveryReference = _requestLine.parmDeliveryReference();
    lines.TransferDateBLDate = _requestLine.parmTransferDateBLDate();
    lines.AirFreightCharges = _requestLine.parmAirFreightCharges();
    lines.DescriptionDetails = _requestLine.parmDescriptionDetails();
    lines.Dateofissue = _requestLine.parmDateOfIssue();
    lines.Dateofsail = _requestLine.parmDateOfSail();
    lines.PurchUnit = _requestLine.parmUOM();
    lines.PurchPrice = _requestLine.parmUnitPrice();
    lines.Amount = _requestLine.parmUnitPrice();
    lines.CurrencyCode = _requestLine.parmAmountInDocCurrency();
    lines.MaterialCode = _requestLine.parmMaterialCode();
    lines.Material = _requestLine.parmMaterial();
    lines.insert();
    //lines.OrderAccount  = _requestLine.parmAccount();
}
